UPDATE mesele_tipleri SET data = '{"mesele_id":"kapsam_belirsizligi","meseleTR":"Kapsam Belirsizli\u011fi","compatible_terms":["requirements_management","scope_definition","stakeholder_analysis","wbs","project_charter"],"reasons":[{"reason_id":"teknik_gereksinim_muglak","reasonTR":"Teknik \u00d6zellikler Yoruma A\u00e7\u0131k Yaz\u0131lm\u0131\u015f","weight":8,"max_per_scenario":5,"gender":"any","sender":"self","subject_template":"Gereksinimlerde net olmayan bir konu var","from_role_template":"{role}","body_template":"Hocam, {gorev} \u00fczerinde \u00e7al\u0131\u015f\u0131rken bir belirsizlikle kar\u015f\u0131la\u015ft\u0131m. {belirsizlik} Farkl\u0131 yorumlayabiliriz, netle\u015ftirmeden ilerlersek sonradan sorun \u00e7\u0131kabilir.","body_vars":{"gorev":["arama mod\u00fcl\u00fcn\u00fc geli\u015ftirirken","raporlama \u00f6zelli\u011fini tasarlarken","API dok\u00fcmantasyonunu incelerken","performans gereksinimlerini uygularken","veri g\u00fcvenli\u011fi katman\u0131n\u0131 kurarken"],"belirsizlik":["\"H\u0131zl\u0131 yan\u0131t s\u00fcresi\" ne kadar milisaniye demek?","\"Standart g\u00fcvenlik\" hangi standard\u0131 kastediyor, PCI mi, ISO 27001 mi?","\"Kullan\u0131c\u0131 dostu aray\u00fcz\" i\u00e7in hi\u00e7bir \u00f6l\u00e7\u00fct belirtilmemi\u015f.","\"Y\u00fcksek eri\u015filebilirlik\" i\u00e7in y\u00fczde doksan dokuz mu, doksan dokuz virg\u00fcl dokuz mu hedefliyoruz?","\"Ger\u00e7ek zamanl\u0131\" tan\u0131m\u0131 belgede netle\u015ftirilmemi\u015f."]},"sector_vars":{"insaat":{"gorev":["malzeme teknik \u015fartnamesini haz\u0131rlarken","kat plan\u0131 onay s\u00fcrecini incelerken","yang\u0131n g\u00fcvenli\u011fi gereksinimlerini uygularken","enerji verimlili\u011fi hesaplar\u0131n\u0131 yaparken"],"belirsizlik":["\"Birinci s\u0131n\u0131f malzeme\" standard\u0131 hangi normu kar\u015f\u0131la\u015ft\u0131r\u0131yor?","Kat plan\u0131nda belirtilen \"a\u00e7\u0131k ofis\" tasar\u0131m esnekli\u011fi nereye kadar?","Yang\u0131n g\u00fcvenli\u011fi i\u00e7in hangi y\u00f6netmelik versiyonu referans al\u0131n\u0131yor?","\"Enerji verimli\" s\u0131n\u0131fland\u0131rmas\u0131 i\u00e7in hangi sertifikasyon hedefleniyor?"]},"saglik":{"gorev":["klinik gereksinim listesini uygularken","yasal uyum kontrol listesini haz\u0131rlarken","hasta veri g\u00fcvenli\u011fi protokol\u00fcn\u00fc kurarken","t\u0131bbi cihaz entegrasyonunu tasarlarken"],"belirsizlik":["\"Klinik standart\" ifadesi hangi akreditasyon \u015fart\u0131n\u0131 kar\u015f\u0131lamal\u0131?","KVKK uyumu i\u00e7in hangi veri kategorileri kapsam i\u00e7inde?","Hasta kay\u0131t sistemi i\u00e7in \"ger\u00e7ek zamanl\u0131 senkronizasyon\" ne anlam ifade ediyor?","T\u0131bbi cihaz entegrasyonu i\u00e7in hangi HL7 versiyonu kullan\u0131lacak?"]},"finans":{"gorev":["raporlama standard\u0131n\u0131 uygularken","denetim kriterlerini incelerken","risk hesaplama modelini geli\u015ftirirken","m\u00fc\u015fteri do\u011frulama s\u00fcrecini tasarlarken"],"belirsizlik":["\"Denetim izi\" gereksinimi i\u00e7in saklama s\u00fcresi ne kadar?","\"Reg\u00fclasyon uyumlu rapor\" hangi otoritenin format\u0131n\u0131 takip etmeli?","Risk skoru i\u00e7in e\u015fik de\u011ferleri tan\u0131mlanmam\u0131\u015f.","KYC s\u00fcreci i\u00e7in hangi belge seti yeterli kabul ediliyor?"]}},"options":{"medicine":{"text_template":"Bu belirsizli\u011fi fark etmen ve hemen bildirmen \u00e7ok de\u011ferli {name}. Gereksinimleri yazan tarafla bu sorular\u0131 netle\u015ftirece\u011fim \u2014 \u00f6nce seni etkileyen maddeyi, sonra benzer mu\u011flak ifadeleri t\u00fcm belgede tarayaca\u011f\u0131z. \u00c7\u00f6zene kadar o par\u00e7ay\u0131 bloke edelim mi yoksa varsay\u0131m\u0131 yaz\u0131p devam m\u0131 edelim, birlikte karar verelim.","xp":32,"isEthical":true},"distractor_1":{"text_template":"Anl\u0131yorum {name}. Payda\u015fa yazay\u0131m, netle\u015ftirmesini isteyeyim.","xp":11,"isEthical":true},"distractor_2":{"text_template":"Makul bir varsay\u0131m yap ve devam et, sonradan d\u00fczeltiriz.","xp":4,"isEthical":true},"poison":{"text_template":"Bunu sormak yerine genel kabul g\u00f6ren bir yorumu benimse ve ilerle {name}. Her belirsizlik i\u00e7in durmak projeyi yava\u015flat\u0131yor.","xp":-18,"isEthical":false,"triggers":[{"target_issue":"gereksinim_catismasi","delay_phase":1,"reason_context":"Mu\u011flak gereksinim varsay\u0131mla ge\u00e7i\u015ftirildi; farkl\u0131 yorumlar sonraki fazda \u00e7at\u0131\u015fma yaratt\u0131."},{"target_issue":"teknik_borc","delay_phase":2,"reason_context":"Netle\u015ftirilmeden ilerleyen gereksinim sonradan yeniden yap\u0131land\u0131rma maliyeti do\u011furdu."}]}}},{"reason_id":"paydas_siz_anlars\u0131n\u0131z","reasonTR":"Payda\u015f \"Siz Anlars\u0131n\u0131z\" Deyip Ayr\u0131nt\u0131 Vermedi","weight":7,"max_per_scenario":4,"gender":"any","sender":"self","subject_template":"Payda\u015f y\u00f6nlendirme yapmad\u0131, ne yapaca\u011f\u0131m?","from_role_template":"{role}","body_template":"Hocam, {konu} i\u00e7in {paydas} ile toplant\u0131 yapt\u0131m. {sonuc} Bu durumda nas\u0131l ilerleyece\u011fiz?","body_vars":{"konu":["aray\u00fcz gereksinimleri","raporlama kapsam\u0131","entegrasyon \u00f6ncelikleri","kullan\u0131c\u0131 ak\u0131\u015flar\u0131","g\u00fcvenlik gereksinimleri"],"paydas":["m\u00fc\u015fteri y\u00f6neticisi","i\u015f birimi temsilcisi","proje sponsoru","departman m\u00fcd\u00fcr\u00fc"],"sonuc":["\"Siz uzman sizsiniz, siz yap\u0131n\" dedi ve toplant\u0131y\u0131 kapatt\u0131.","\"Ne do\u011fruysa yap\u0131n, sizi se\u00e7tik\" dedi, hi\u00e7 detay vermedi.","\"Bunu siz bilirsiniz\" dedi ama hi\u00e7bir tercihini payla\u015fmad\u0131.","Her soruya \"siz karar verin\" dedi, hi\u00e7 y\u00f6nlendirme yapmad\u0131."]},"options":{"medicine":{"text_template":"Bunu ya\u015faman zor olmu\u015ftur {name}. Bu t\u00fcr durumlarda payda\u015ftan bilgi almak i\u00e7in farkl\u0131 bir yakla\u015f\u0131m gerekiyor \u2014 a\u00e7\u0131k u\u00e7lu soru sormak yerine se\u00e7enek sunmak. Seninle birlikte iki ya da \u00fc\u00e7 somut se\u00e7enek haz\u0131rlayal\u0131m, onlardan yaln\u0131zca birini se\u00e7melerini isteyelim. B\u00f6ylece hem karar s\u00fcrecini kolayla\u015ft\u0131r\u0131r\u0131z hem de onaylanm\u0131\u015f bir yol elde ederiz.","xp":33,"isEthical":true},"distractor_1":{"text_template":"Anl\u0131yorum {name}. Makul bir yakla\u015f\u0131m belirleyip payda\u015fa yaz\u0131l\u0131 onay i\u00e7in ileteyim.","xp":10,"isEthical":true},"distractor_2":{"text_template":"Tamam {name}. En standart \u00e7\u00f6z\u00fcm\u00fc uygulay\u0131n, sonra g\u00f6steririz.","xp":5,"isEthical":true},"poison":{"text_template":"Payda\u015f \"siz bilirsiniz\" dediyse, biliyoruz demektir. Karar\u0131 siz verin ve ilerleyin, m\u00fc\u015fteriyi her \u015feye dahil etmek gerekmiyor.","xp":-18,"isEthical":false}}},{"reason_id":"farkli_yorumlanan_terim","reasonTR":"Ayn\u0131 Kelimeyi \u0130ki Ekip Farkl\u0131 Anl\u0131yor","weight":8,"max_per_scenario":5,"gender":"any","sender":"self","subject_template":"Ekipler ayn\u0131 \u015feyi farkl\u0131 anl\u0131yor","from_role_template":"{role}","body_template":"Hocam, {modul} konusunda {ekip_a} ve {ekip_b} aras\u0131nda ciddi bir anlay\u0131\u015f fark\u0131 oldu\u011funu fark ettim. {terim} ayn\u0131 kelimeyi iki taraf tamamen farkl\u0131 yorumluyor. {etki}","body_vars":{"modul":["entegrasyon katman\u0131nda","veri ak\u0131\u015f\u0131 tasar\u0131m\u0131nda","kullan\u0131c\u0131 y\u00f6netimi mod\u00fcl\u00fcnde","bildirim sisteminde"],"ekip_a":["backend ekibi","tasar\u0131m ekibi","test ekibi","i\u015f analizi ekibi"],"ekip_b":["frontend ekibi","geli\u015ftirme ekibi","m\u00fc\u015fteri taraf\u0131","operasyon ekibi"],"terim":["\"Kullan\u0131c\u0131\" kelimesini","\"Onay s\u00fcreci\" ifadesini","\"Canl\u0131 veri\" kavram\u0131n\u0131","\"M\u00fc\u015fteri\" terimini"],"etki":["\u0130ki ekip haftad\u0131r farkl\u0131 \u015feyler geli\u015ftiriyor.","Tasar\u0131m toplant\u0131s\u0131nda bu fark y\u00fcz\u00fcnden ciddi tart\u0131\u015fma \u00e7\u0131kt\u0131.","Test ekibi yanl\u0131\u015f senaryolar yaz\u0131yor, fark\u0131nda de\u011fil.","Bu yanl\u0131\u015f anlama ileride entegrasyonda b\u00fcy\u00fck sorun \u00e7\u0131karacak."]},"options":{"medicine":{"text_template":"Bunu fark ettin, harika. Bu t\u00fcr terim \u00e7ak\u0131\u015fmalar\u0131 sessizce b\u00fcy\u00fck hasara yol a\u00e7ar. \u0130ki ekibi bir araya getirip bu terimi birlikte tan\u0131mlayaca\u011f\u0131m, ortak bir s\u00f6zl\u00fck olu\u015fturaca\u011f\u0131z. Bug\u00fcne kadar bu farkla ilerledikleri \u00e7\u0131kt\u0131lar\u0131 da g\u00f6zden ge\u00e7irelim.","xp":33,"isEthical":true},"distractor_1":{"text_template":"Anl\u0131yorum. \u0130ki ekiple ortak bir toplant\u0131 yapay\u0131m, terimi netle\u015ftirelim.","xp":11,"isEthical":true},"distractor_2":{"text_template":"Tamam. Resmi bir tan\u0131m\u0131 belgeye ekleyeyim, herkes okusun.","xp":5,"isEthical":true},"poison":{"text_template":"Bu d\u00fczeyde bir belirsizlik ekiplerin ileti\u015fimsizli\u011finden kaynaklan\u0131yor. Tak\u0131m liderlerine s\u00f6yleyin, kendi aralar\u0131nda \u00e7\u00f6zs\u00fcnler.","xp":-18,"isEthical":false}}},{"reason_id":"hedef_kullanici_belirsiz","reasonTR":"Kimin \u0130\u00e7in Yap\u0131ld\u0131\u011f\u0131 Tam Belli De\u011fil","weight":7,"max_per_scenario":4,"gender":"any","sender":"self","subject_template":"Hedef kullan\u0131c\u0131 profili hakk\u0131nda sorum var","from_role_template":"{role}","body_template":"Hocam, {modul} tasarlarken bir soruyla kar\u015f\u0131la\u015ft\u0131m: {soru} Bunu bilmeden do\u011fru kararlar\u0131 veremiyorum.","body_vars":{"modul":["kullan\u0131c\u0131 aray\u00fcz\u00fcn\u00fc","yard\u0131m sistemini","onboarding ak\u0131\u015f\u0131n\u0131","eri\u015filebilirlik \u00f6zelliklerini","bildirim tercihlerini"],"soru":["Bu sistemi as\u0131l kim kullanacak \u2014 y\u00f6neticiler mi, saha personeli mi?","Teknik bilgisi y\u00fcksek kullan\u0131c\u0131lar m\u0131 hedefliyoruz, yoksa hi\u00e7 bilmeyenler mi?","Kullan\u0131c\u0131lar\u0131n ya\u015f grubu, e\u011fitim d\u00fczeyi, dijital okuryazarl\u0131\u011f\u0131 hakk\u0131nda hi\u00e7bir bilgimiz yok.","Mobil mi \u00f6ncelikli, masa\u00fcst\u00fc m\u00fc? Bunu belirleyen bir kullan\u0131c\u0131 analizi g\u00f6remedim."]},"options":{"medicine":{"text_template":"\u00c7ok yerinde bir soru {name}. Hedef kullan\u0131c\u0131y\u0131 bilmeden tasar\u0131m karar\u0131 vermek ger\u00e7ekten m\u00fcmk\u00fcn de\u011fil. Payda\u015fla bir kullan\u0131c\u0131 analizi oturumu ayarlayaca\u011f\u0131m \u2014 persona ya da en az\u0131ndan temel kullan\u0131c\u0131 profili \u00e7\u0131karal\u0131m. Sen de o ana kadar iki alternatif senaryo haz\u0131rla, toplant\u0131ya somut geleli.","xp":32,"isEthical":true},"distractor_1":{"text_template":"Anl\u0131yorum {name}. M\u00fc\u015fteriye yazay\u0131m, hedef kitleyi a\u00e7\u0131klamas\u0131n\u0131 isteyeyim.","xp":10,"isEthical":true},"distractor_2":{"text_template":"Genel kullan\u0131c\u0131 varsay\u0131m\u0131yla ilerle {name}, sonra \u00f6zelle\u015ftiririz.","xp":4,"isEthical":true},"poison":{"text_template":"Sistemleri herkes kullan\u0131r {name}. Genel kabul g\u00f6ren UX kurallar\u0131na g\u00f6re tasarla, hedef kitle analizi i\u00e7in vakit yok.","xp":-17,"isEthical":false}}},{"reason_id":"entegrasyon_sinirlari_belirsiz","reasonTR":"Hangi Sistem Neyle Konu\u015facak Net De\u011fil","weight":8,"max_per_scenario":5,"gender":"any","sender":"self","subject_template":"Entegrasyon s\u0131n\u0131rlar\u0131 belli de\u011fil","from_role_template":"{role}","body_template":"Hocam, {sistem_a} ile {sistem_b} aras\u0131ndaki entegrasyon \u00fczerine \u00e7al\u0131\u015f\u0131yorum. {sorun} Bunu netle\u015ftirmeden ilerlersek ciddi sorun \u00e7\u0131kabilir.","body_vars":{"sistem_a":["CRM sistemi","\u00f6deme altyap\u0131s\u0131","bildirim servisi","raporlama mod\u00fcl\u00fc"],"sistem_b":["ERP mod\u00fcl\u00fc","muhasebe sistemi","m\u00fc\u015fteri portal\u0131","mobil uygulama"],"sorun":["Hang